import type { MissionState } from "../../api";

function clip(s: string, n: number) {
  if (!s) return "—";
  return s.length > n ? `${s.slice(0, n - 1)}…` : s;
}

export default function MissionPanel({ mission }: { mission: MissionState }) {
  const runtime = mission?.runtime;
  return (
    <div className="kv">
      <div className="kv-row">
        <span className="kv-key">headline</span>
        <span className="kv-val truncate">{clip(mission?.headline || "idle", 60)}</span>
      </div>
      <div className="kv-row">
        <span className="kv-key">model</span>
        <span className="kv-val">{runtime?.model || "?"}</span>
        <span className="kv-key">iter</span>
        <span className="kv-val">{runtime?.iteration ?? 0}</span>
      </div>
      <div className="kv-row">
        <span className="kv-key">rate</span>
        <span className="kv-val">1m {mission?.rate1m ?? 0} · 5m {mission?.rate5m ?? 0}</span>
      </div>
      <div className="kv-row">
        <span className="kv-key">last in</span>
        <span className="kv-val truncate muted">{clip((mission?.lastInbound?.content || "").replace(/\s+/g, " "), 60)}</span>
      </div>
      <div className="kv-row">
        <span className="kv-key">last out</span>
        <span className="kv-val truncate muted">{clip((mission?.lastOutbound?.content || "").replace(/\s+/g, " "), 60)}</span>
      </div>
    </div>
  );
}

import type { HermesEvent } from "../../api";
import { colorFor } from "../../visualEngine";

type Props = {
  events: HermesEvent[];
  onSelect?: (event: HermesEvent) => void;
};

export default function HermesLivePanel({ events, onSelect }: Props) {
  if (!events.length) return <div className="muted">waiting for events…</div>;
  return (
    <ul className="row-list event-list">
      {events.slice(0, 12).map((e) => (
        <li
          key={e.id}
          className="row event-row"
          style={{ color: colorFor(e.type) }}
          onClick={() => onSelect?.(e)}
        >
          <span className="row-time">{(e.createdAt || "").slice(11, 19)}</span>
          <span className="row-tag">{e.type.toUpperCase()}</span>
          <span className="row-id">{e.role || ""}</span>
          <span className="row-content truncate">{(e.content || "").replace(/\s+/g, " ")}</span>
        </li>
      ))}
    </ul>
  );
}

import type { ChangelogEntry } from "../../api";

export default function ChangelogPanel({ entries }: { entries: ChangelogEntry[] }) {
  if (!entries.length) return <div className="muted">no changelog yet</div>;
  return (
    <ul className="row-list">
      {entries.slice(0, 6).map((e, i) => (
        <li key={`${e.date}-${i}`} className="row">
          <span className="row-time">{e.date}</span>
          <span className="row-content truncate">{e.title}</span>
        </li>
      ))}
    </ul>
  );
}
